# Bitwarden Secrets Manager — required secrets
# Create these in your BWS project. The secret name becomes the environment variable name.
# Set BWS_ACCESS_TOKEN in your shell before running start-jamf.sh or start-intune.sh.

# JAMF Pro (start-jamf.sh)
JAMF_URL              Base URL of your JAMF Pro instance, e.g. https://yourorg.jamfcloud.com
JAMF_CLIENT_ID        OAuth2 client ID — create under JAMF Pro > Settings > API Roles and Clients
JAMF_CLIENT_SECRET    OAuth2 client secret for the above client

# Microsoft Intune (start-intune.sh)
AZURE_TENANT_ID       Azure AD tenant ID
AZURE_CLIENT_ID       App registration client ID (needs DeviceManagementManagedDevices.Read.All)
AZURE_CLIENT_SECRET   App registration client secret
